scwin.f_Print = function (flag) {
  ds_OZ.removeAll();
  ds_OZ.insertRow();
  ds_OZ.setCellData(0, "hhblno", ed_hhblno.getValue());
  ds_OZ.setCellData(0, "mhno", lc_dateTitle.getValue());
  if (ed_hhblno_2.getValue() != "") {
    let r2 = ds_OZ.insertRow();
    ds_OZ.setCellData(r2, "hhblno", ed_hhblno_2.getValue());
    ds_OZ.setCellData(r2, "mhno", lc_hhpaynm.getValue());
  }
  if (ed_hhblno_3.getValue() != "") {
    let r3 = ds_OZ.insertRow();
    ds_OZ.setCellData(r3, "hhblno", ed_hhblno_3.getValue());
    ds_OZ.setCellData(r3, "mhno", lc_mhno_3.getValue());
  }
  if (ed_hhblno_4.getValue() != "") {
    let r4 = ds_OZ.insertRow();
    ds_OZ.setCellData(r4, "hhblno", ed_hhblno_4.getValue());
    ds_OZ.setCellData(r4, "mhno", lc_mhno_4.getValue());
  }
  if (ed_hhblno_5.getValue() != "") {
    let r5 = ds_OZ.insertRow();
    ds_OZ.setCellData(r5, "hhblno", ed_hhblno_5.getValue());
    ds_OZ.setCellData(r5, "mhno", lc_mhno_5.getValue());
  }
  OZStartBatch();
  for (let m = 0; m < ds_OZ.getRowCount(); m++) {
    let odiParam = new ODIParam("se_105_01_03");
    odiParam.add("KCOMCD", scwin.hd_kcomcd);
    odiParam.add("HHBLNO", ds_OZ.getCellData(m, "hhblno"));
    odiParam.add("MHNO", ds_OZ.getCellData(m, "mhno"));
    odiParam.add("ONBOARD", lc_dateTitle.getValue());
    odiParam.add("PAYAT", lc_hhpaynm.getValue());
    let v_bank = "";
    let chkBankVal = chb_bank.getValue();
    if (chkBankVal != "" && chkBankVal != "0") {
      v_bank = "1";
      odiParam.add("RMK", v_bank);
    } else {
      v_bank = "0";
      odiParam.add("RMK", v_bank);
    }
    odiParam.add("USERID", scwin.userId);
    let formParam = new FormParam();
    let viewerParam = new ViewerParam();
    viewerParam.add("viewer.useprogressbar", "false");
    let filename = ds_OZ.getCellData(m, "hhblno");
    switch (rd_prttype.getValue()) {
      case "K":
        filename += "_IMAGE BL";
        break;
      case "C":
        filename += "_CHECK BL";
        break;
      case "S":
        filename += "_SURRENDER BL";
        break;
      case "P":
        filename += "_COPY BL";
        break;
    }
    viewerParam.add("export.filename", filename);
    viewerParam.add("export.format", "pdf");
    viewerParam.add("export.path", "C:\\OZExport");
    if (flag == 0) {
      if (rd_prttype.getValue() == "K") {
        $c.gus.cfOZPreview($p, "/il/seaout/se_105_01_03a.ozr", odiParam, viewerParam, formParam);
      } else if (rd_prttype.getValue() == "C") {
        $c.gus.cfOZPreview($p, "/il/seaout/se_105_01_03b.ozr", odiParam, viewerParam, formParam);
      } else if (rd_prttype.getValue() == "S") {
        $c.gus.cfOZPreview($p, "/il/seaout/se_105_01_03c.ozr", odiParam, viewerParam, formParam);
      } else if (rd_prttype.getValue() == "P") {
        $c.gus.cfOZPreview($p, "/il/seaout/se_105_01_03d.ozr", odiParam, viewerParam, formParam);
      }
    } else if (flag == 1) {
      if (rd_prttype.getValue() == "K") {
        $c.gus.cfOZPreview($p, "/il/seaout/se_105_01_03a_1.ozr", odiParam, viewerParam, formParam);
      } else if (rd_prttype.getValue() == "C") {
        $c.gus.cfOZPreview($p, "/il/seaout/se_105_01_03b_1.ozr", odiParam, viewerParam, formParam);
      } else if (rd_prttype.getValue() == "S") {
        $c.gus.cfOZPreview($p, "/il/seaout/se_105_01_03c_1.ozr", odiParam, viewerParam, formParam);
      } else if (rd_prttype.getValue() == "P") {
        $c.gus.cfOZPreview($p, "/il/seaout/se_105_01_03d_1.ozr", odiParam, viewerParam, formParam);
      }
    }
  }
  OZExecuteBatch();
};
