scwin.sbm_loadMhno_submitdone = async function (e) {
  let idx = scwin.mhnoLoadingIdx;
  let targetDs = null;
  let targetLc = null;
  let houseLabel = "";
  switch (idx) {
    case 1:
      targetDs = ds_hmhno;
      targetLc = lc_dateTitle;
      houseLabel = "House No 1";
      break;
    case 2:
      targetDs = ds_hmhno_2;
      targetLc = lc_hhpaynm;
      houseLabel = "House No 2";
      break;
    case 3:
      targetDs = ds_hmhno_3;
      targetLc = lc_mhno_3;
      houseLabel = "House No 3";
      break;
    case 4:
      targetDs = ds_hmhno_4;
      targetLc = lc_mhno_4;
      houseLabel = "House No 4";
      break;
    case 5:
      targetDs = ds_hmhno_5;
      targetLc = lc_mhno_5;
      houseLabel = "House No 5";
      break;
  }
  if (targetDs && targetDs.getRowCount() == 0) {
    if (scwin.statusFlag != "C") {
      await $c.gus.cfAlertMsg($p, MSG_CM_ERR_049, [houseLabel]);
    }
    targetDs.insertRow();
    targetDs.setCellData(targetDs.getRowPosition(), "code", "NONE");
    targetDs.setCellData(targetDs.getRowPosition(), "name", "NONE");
    if (targetLc) {
      targetLc.setSelectedIndex(0);
    }
  }
  if (idx == 1 && scwin.mhnoFlag == "1") {
    await scwin.f_Retrieve();
    scwin.mhnoFlag = "0";
  }
};
